package com.veetu.vadagai.tenant;import com.veetu.vadagai.property.PropertyRepository;import com.veetu.vadagai.tenant.TenantDtos.*;import com.veetu.vadagai.user.*;import lombok.RequiredArgsConstructor;import org.springframework.security.crypto.password.PasswordEncoder;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.util.*;
@Service @RequiredArgsConstructor public class TenantService{private final TenantRepository tenants;private final UserRepository users;private final PropertyRepository properties;private final PasswordEncoder encoder;@Transactional public TenantResponse add(TenantRequest r){var property=properties.findById(r.propertyId()).orElseThrow();var user=users.findByEmailIgnoreCaseAndDeletedFalse(r.email()).orElseGet(()->users.save(User.builder().email(r.email().toLowerCase()).fullName(r.fullName()).mobile(r.mobile()).passwordHash(encoder.encode("Tenant@12345")).roles(Set.of(Role.TENANT)).emailVerified(true).build()));property.setOccupied(true);var t=tenants.save(TenantProfile.builder().user(user).property(property).emergencyContact(r.emergencyContact()).moveInDate(r.moveInDate()).build());return map(t);}public List<TenantResponse> ownerTenants(UUID ownerId){return tenants.findByPropertyOwnerIdAndDeletedFalse(ownerId).stream().map(this::map).toList();}TenantResponse map(TenantProfile t){return new TenantResponse(t.getId(),t.getUser().getEmail(),t.getUser().getFullName(),t.getProperty().getTitle(),t.getEmergencyContact(),t.getMoveInDate());}}
